VALUES
  ('pukao-8b44517b-moex-00276', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '下列何種情形，不適用公法上不當得利返還請求權？', '["甲公務員因溢領一次性退休金之給付，主管機關撤銷原核定處分後，命甲返還溢領金額", "乙繳付工業區開發管理基金後，因非可歸責於己之事由而未設廠，向主管機關請求返還", "丙之土地經徵收並領取補償金後，經查計算標準錯誤有溢領情形，補償機關請求丙返還", "丁廠商參與政府採購得標並已完工驗收，主管機關未給付工程尾款，丁訴請該機關返還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00277', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '關於行政機關與人民締結互負給付義務之行政契約，下列敘述何者錯誤？', '["契約中應約定人民給付之目的", "契約之締結應以書面為之", "人民之給付與行政機關之給付未相當者，該契約無效", "人民之給付不限於行政機關之特定用途"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00278', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '需用土地人申請徵收土地前，與土地所有人達成之協議價購，其法律性質為何？', '["行政契約", "行政處分", "私法契約", "事實行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00279', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '依最高行政法院實務見解，下列何者非屬觀念通知？', '["主管機關同意甫成立之公寓大廈管理委員會依法所為之報備", "公平交易委員會對檢舉人所為檢舉不成立之函文", "主管機關通知人民自行拆除違章建築之違章建築拆除通知單", "主管機關對人民團體選任職員簡歷冊之異動所為之核備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00280', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '依據行政罰法與學理之見解，關於行政罰之敘述，下列何者正確？', '["為避免行政機關執法困擾，行政罰法得類推適用刑法共犯制度之規定", "個別法規有推定過失特別規定時，應優先於行政罰法責任條件之規定", "對同一違反義務行為，禁止同時科處行政罰並作成單純不利益行政處分", "對違反行政法上義務之行為，地方行政機關僅得依地方議會制定自治條例處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00281', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '依最高行政法院裁判見解，關於行政罰法中法律變更時之適用原則之敘述，下列何者錯誤？', '["行政罰法規定行為後法律有變更者，適用行政機關最初裁處時之法律，為從新原則之具體化", "行為後法律雖有變更，如裁處前之法律係有利於受處罰者，適用最有利於受處罰者之規定", "行政機關依法律授權所為之公告，因會對外發生規範效力，故其內容之變更亦屬法律變更", "行政機關為行使裁量權所訂頒之裁量基準，因非屬法律，故其變更即非屬法律變更之情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00282', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '甲向主管機關申領身心障礙給付後，檢察官以詐欺取財罪對甲作成緩起訴處分。主管機關乃依法就其 詐領給付之行為，處以給付額兩倍之罰鍰。其裁處權時效應如何起算？', '["自主管機關知悉甲違法時起算", "自甲持不實資料向主管機關提出申請時起算", "自甲受領身心障礙給付時起算", "自檢察官緩起訴處分確定時起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00283', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '下列何者屬於行政罰法之規制範圍？', '["證券交易法第 59 條第 1 項規定：「證券商自受領證券業務特許證照，或其分支機構經許可並登記 後，於三個月內未開始營業，或雖已開業而自行停止營業連續三個月以上時，主管機關得撤銷其特 許或許可。」", "稅捐稽徵法第24條第1項前段規定：「納稅義務人欠繳應納稅捐者，稅捐稽徵機關得就納稅義務人 相當於應繳稅捐數額之財產，通知有關機關，不得為移轉或設定他項權利。」", "所得稅法第43條之2第1項規定：「自一百年度起，營利事業對關係人之負債占業主權益超過一定 比率者，超過部分之利息支出不得列為費用或損失。」", "道路交通管理處罰條例第12條第1項規定：「汽車有下列情形之一者，處汽車所有人新臺幣三千六 百元以上一萬零八百元以下罰鍰，......。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00284', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '甲因積欠交通違規罰單新臺幣18,000元，主管機關經催討後仍未繳納，移送行政執行。依行政執行法 規定，執行機關之下列執行行為何者違法？', '["於星期一上午8時對於甲之動產進行查封", "於履行期間屆滿後3年通知甲報告其財產狀況，之後逾3年始進行查封", "命甲報告財產狀況而甲不為報告，認應強制其到場而聲請法院裁定拘提", "於查明甲之經濟狀況後，認為其無法一次完納，經主管機關同意准其分期繳納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('pukao-8b44517b-moex-00285', 'pukao-8b44517b', 'pukao-8b44517b-moex-110-d1a761c9', 'sub-pukao-8b44517b-03', NULL, 'single_choice', '關於行政執行法上之管收，下列敘述何者正確？', '["義務人不繳納怠金及代履行費用，並無適用管收相關規定之可能", "涉及義務人人身自由之限制，行政執行官應自拘提時起24小時內作成管收處分", "義務人如不服管收之決定，得準用民事訴訟法相關規定提出救濟，但管收之執行並不停止", "管收期限最長為3個月，義務人經管收期滿後，所負之公法上金錢給付義務視為已履行而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:07+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "407", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "勞工行政"}'::jsonb, NULL)
